 42→	renderSearchPageHtml({
 43→		result,
 44→		tags,
 45→	}: {
 46→		result: NeuralSearchResponseDto | null;
 47→		tags: string[];
 48→	}): string {
 49→		const queryValue = result?.query ?? '';
 50→		const tagsValue = tags.join(', ');
 51→
 52→		const productCards = result
 53→			? result.products
 54→					.map(
 55→						(p) => `
 56→			<div style="border:1px solid #ddd;border-radius:8px;padding:12px;width:220px;text-align:center;background:#fff;display:flex;flex-direction:column;align-items:center;">
 57→				<img src="${p.style_card_image_url ?? ''}" alt="${p.name}" style="width:200px;height:200px;object-fit:contain;border-radius:4px;" onerror="this.src='data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 width=%22200%22 height=%22200%22><rect fill=%22%23eee%22 width=%22200%22 height=%22200%22/><text x=%2250%%22 y=%2250%%22 dominant-baseline=%22middle%22 text-anchor=%22middle%22 fill=%22%23999%22 font-size=%2214%22>No Image</text></svg>'"/>
 58→				<div style="margin-top:8px;font-weight:600;font-size:14px;min-height:40px;">${p.name}</div>
 59→				<div style="margin-top:4px;font-size:11px;color:#2563eb;font-weight:500;">Confidence: ${String(p.confidenceScore ?? 0)}%</div>
 60→				<div style="color:#555;font-size:12px;margin-top:4px;">${p.primary_category_name ?? ''}</div>
 61→				<div style="color:#666;font-size:11px;margin-top:2px;">${p.product_type ?? ''}</div>
 62→				<div style="color:#777;font-size:11px;margin-top:2px;">${p.manufacturer ?? ''}</div>
 63→				<div style="color:#888;font-size:11px;margin-top:2px;">${p.brand?.join(', ') ?? ''}</div>
 64→			</div>`,
 65→					)
 66→					.join('')
 67→			: '';
 68→
 69→		const resultsSection = result
 70→			? `<p style="margin:16px 0 8px;">Query: <strong>${result.query}</strong>${tags.length ? ` | Tags: <strong>${tags.join(', ')}</strong>` : ''} | Results: ${result.total}</p>
 71→			<div style="display:flex;flex-wrap:wrap;gap:16px;">${productCards}</div>`
 72→			: '';
 73→
 74→		return `<!DOCTYPE html>
 75→<html><head><meta charset="utf-8"><title>Neural Search</title></head>
 76→<body style="font-family:system-ui,sans-serif;margin:20px;background:#f5f5f5;">
 77→	<h2>Neural Search</h2>
 78→	<form id="searchForm" style="margin-bottom:16px;">
 79→		<div style="display:flex;gap:8px;margin-bottom:8px;">
 80→			<input id="searchInput" name="q" type="text" value="${queryValue}" placeholder="Describe what you're looking for..."
 81→				style="flex:1;max-width:500px;padding:10px 14px;font-size:15px;border:1px solid #ccc;border-radius:6px;outline:none;" />
 82→			<button type="submit"
 83→				style="padding:10px 20px;font-size:15px;background:#2563eb;color:#fff;border:none;border-radius:6px;cursor:pointer;">
 84→				Ask AI
 85→			</button>
 86→		</div>
 87→		<div style="display:flex;gap:8px;align-items:center;">
 88→			<input id="tagsInput" type="text" value="${tagsValue}" placeholder="Category tags (comma-separated, e.g. T-Shirts, Apparel)"
 89→				style="flex:1;max-width:500px;padding:8px 12px;font-size:13px;border:1px solid #ccc;border-radius:6px;outline:none;" />
 90→		</div>
 91→	</form>
 92→	<div id="results">${resultsSection}</div>
 93→	<script>
 94→		document.getElementById('searchForm').addEventListener('submit', function(e) {
 95→			e.preventDefault();
 96→			var q = document.getElementById('searchInput').value.trim();
 97→			if (!q) return;
 98→			var url = '/api/v1/neural-search/view?q=' + encodeURIComponent(q);
 99→			var tagsRaw = document.getElementById('tagsInput').value.trim();
100→			if (tagsRaw) {
101→				var tags = tagsRaw.split(',').map(function(t) { return t.trim(); }).filter(Boolean);
102→				tags.forEach(function(tag) { url += '&tags=' + encodeURIComponent(tag); });
103→			}
104→			window.location.href = url;
105→		});
106→	</script>
107→</body></html>`;
108→	}
109→}
