 64→	private getModelId(): string {
 65→		if (!this.modelId) {
 66→			throw new Error(
 67→				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
 68→			);
 69→		}
 70→		return this.modelId;
