 73→	private detectBrand({ text }: { text: string }): string | null {
 74→		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
 75→		for (const brand of sorted) {
 76→			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 77→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
 78→				return brand;
 79→			}
 80→		}
 81→		return null;
 82→	}
