298→	async searchProducts({
299→		queryText,
300→		size = NEURAL_SEARCH_LIMIT,
301→		tags,
302→	}: {
303→		queryText: string;
304→		size?: number;
305→		tags?: string[];
306→	}): Promise<IOpensearchProduct[]> {
307→		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
308→		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
309→		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
310→		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
311→		const brand = this.detectBrand({ text: sanitizedQuery });
312→
313→		const baseFilters: object[] = [{ term: { status: 'active' } }];
314→
315→		if (genderProductTypes) {
316→			baseFilters.push({ terms: { product_type: genderProductTypes } });
317→		}
318→
319→		const priceBoosts: object[] =
320→			priceLevels?.map((level) => ({
321→				term: { price_level: { value: level, boost: 1.5 } },
322→			})) ?? [];
323→
324→		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand], boost: 2 } }] : [];
325→
326→		const categoryBoosts: object[] = tags?.length
327→			? [
328→					{ terms: { primary_category_name: { value: tags, boost: 1.5 } } },
329→					{ terms: { broad_category_names: { value: tags, boost: 1 } } },
330→					{ terms: { sub_category_names: { value: tags, boost: 1 } } },
331→				]
332→			: [];
333→
334→		const hits = await this.opensearchService.search({
335→			indexName: this.indexName,
336→			searchPipeline: 'hybrid-search-pipeline',
337→			body: {
338→				size,
339→				min_score: 0.4,
340→				query: {
341→					hybrid: {
342→						queries: [
343→							{
344→								bool: {
345→									should: [
346→										{
347→											match_phrase: {
348→												general_comments: { query: normalizedQuery, boost: 0.1 },
349→											},
350→										},
351→										{
352→											match_phrase: { features: { query: normalizedQuery, boost: 0.1 } },
353→										},
354→										{ match_phrase: { name: { query: normalizedQuery, boost: 0.1 } } },
355→										...priceBoosts,
356→										...brandBoosts,
357→										...categoryBoosts,
358→									],
359→									filter: baseFilters,
360→								},
361→							},
362→							{
363→								neural: {
364→									product_embedding: {
365→										query_text: normalizedQuery,
366→										model_id: this.getModelId(),
367→										k: size * 5,
368→										filter: { bool: { filter: baseFilters } },
369→									},
370→								},
371→							},
372→						],
373→					},
374→				},
375→				collapse: { field: 'product_id' },
376→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
377→			},
378→		});
379→
380→		const maxScore = Math.max(...hits.map((hit) => hit._score), 1);
381→
382→		return hits.map((hit) => ({
383→			...(hit._source as IOpensearchProduct),
384→			_id: hit._id,
385→			confidenceScore: Math.round((hit._score / maxScore) * 100),
386→		}));
387→	}
