389→	private normalizeCondensedFeatures({
390→		condensedFeatures,
391→	}: {
392→		condensedFeatures: unknown;
393→	}): string[] | null {
394→		if (condensedFeatures === null || condensedFeatures === undefined) {
395→			return null;
396→		}
397→
398→		if (typeof condensedFeatures === 'string') {
399→			return [condensedFeatures];
400→		}
401→
402→		if (Array.isArray(condensedFeatures)) {
403→			return condensedFeatures.map(String);
404→		}
405→
406→		if (typeof condensedFeatures === 'object') {
407→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
408→				Array.isArray(value) ? value.map(String) : [String(value)],
409→			);
410→		}
411→
412→		return [JSON.stringify(condensedFeatures)];
413→	}
