415→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
416→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
417→			condensedFeatures: style.condensed_features,
418→		});
419→		const priceLvlMap: Record<string, string> = {
420→			1: 'Budget',
421→			2: 'Mid-range',
422→			3: 'Premium',
423→		};
424→		const mappedPriceLevel: string | null =
425→			style.price_level && priceLvlMap[String(style.price_level)]
426→				? (priceLvlMap[String(style.price_level)] ?? null)
427→				: (priceLvlMap['2'] ?? null);
428→
429→		const parts: string[] = [
430→			...(style.name ? [this.cleanText({ text: style.name })] : []),
431→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
432→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
433→			...(style.brand?.length
434→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
435→				: []),
436→			...(normalizedCondensedFeatures?.length
437→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
438→				: []),
439→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
440→			...(style.primary_category_name
441→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
442→				: []),
443→			...(style.manufacturer
444→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
445→				: []),
446→			...(style.sub_category_names?.length
447→				? [
448→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
449→					]
450→				: []),
451→			...(style.decoration_method
452→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
453→				: []),
454→			...(style.features
455→				? [`Features: ${this.cleanText({ text: style.features })}`]
456→				: []),
457→		];
458→
459→		const combinedText = parts.filter(Boolean).join('. ');
460→
461→		this.logger.debug(
462→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
463→		);
464→
465→		return combinedText;
466→	}
467→
468→	private cleanText({ text }: { text: string | null | undefined }): string {
469→		if (!text) return '';
470→		return text
471→			.replace(/\r\n|\r|\n/g, ' ')
472→			.replace(/[*#]+\s?/g, '')
473→			.replace(/<[^>]*>/g, '')
474→			.replace(/\s{2,}/g, ' ')
475→			.trim();
476→	}
